{"code": "import json
import re

# Load latest release for each NPM package
packages_file = locals()['var_functions.query_db:14']
with open(packages_file, 'r') as f:
    packages = json.load(f)

latest_packages = {}
for pkg in packages:
    if pkg['System'] == 'NPM':
        try:
            vinfo = json.loads(pkg['VersionInfo'])
            if vinfo.get('IsRelease'):
                key = pkg['Name']
                ordinal = vinfo.get('Ordinal', 0)
                if key not in latest_packages or ordinal > latest_packages[key]['Ordinal']:
                    latest_packages[key] = {
                        'Name': key,
                        'Version': pkg['Version'],
                        'Ordinal': ordinal
                    }
        except:
            pass

# Load mappings
mappings_file = locals()['var_functions.query_db:12']
with open(mappings_file, 'r') as f:
    mappings = json.load(f)

mappings_dict = {}
for m in mappings:
    key = (m['System'], m['Name'])
    if key not in mappings_dict:
        mappings_dict[key] = m['ProjectName']

# Load project stars
projects_file = locals()['var_functions.query_db:22']
with open(projects_file, 'r') as f:
    projects = json.load(f)

project_stars = {}
for proj in projects:
    info = proj['Project_Information']
    stars_match = re.search(r'(\d+(?:,\d+)*) stars', info)
    if stars_match:
        stars = int(stars_match.group(1).replace(',', ''))
        if stars > 0:
            proj_name_match = re.search(r'(?:project|repository)\s+([a-zA-Z0-9_.-]+/[a-zA-Z0-9_.-]+)', info)
            if proj_name_match:
                project_name = proj_name_match.group(1)
                project_stars[project_name] = stars

# Match packages to stars
package_results = []
for key, pkg in latest_packages.items():
    if key in mappings_dict:
        project_name = mappings_dict[key]
        stars = project_stars.get(project_name, 0)
        if stars > 0:
            package_results.append({
                'Name': pkg['Name'],
                'Version': pkg['Version'],
                'Stars': stars
            })

# Get top 5
top5 = sorted(package_results, key=lambda x: x['Stars'], reverse=True)[:5]

print('Top 5 NPM packages by GitHub stars:')
for pkg in top5:
    print(f"{pkg['Name']} v{pkg['Version']}: {pkg['Stars']} stars")

result = top5
print('__RESULT__:')
print(json.dumps(result))"}
